SELECT COUNT(*)
FROM item


	item_usage = 'Y'


		AND item_type = #{searchType}



		AND (
		UPPER(item_name) LIKE UPPER('%' || #{searchKeyword}
		|| '%')
		OR UPPER(item_id) LIKE UPPER('%' || #{searchKeyword} || '%')
		)

SELECT * FROM ( SELECT ROWNUM RN, I.* FROM ( SELECT item_id AS itemId, item_name AS itemName, item_type AS itemType, item_unit AS unit, item_spec AS spec, item_unit_price AS unitPrice, item_whtype AS itemWhType, item_usedate AS useDate, item_safety_stock AS safetyStock, item_usage AS itemUsage FROM item
item_usage = 'Y'
AND item_type = #{searchType}
AND ( UPPER(item_name) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(item_id) LIKE UPPER('%' || #{searchKeyword} || '%') )
ORDER BY CASE WHEN item_type = '30' THEN 1 WHEN item_type = '20' THEN 2 WHEN item_type = '10' THEN 3 WHEN item_type = '40' THEN 4 ELSE 5 END, item_id DESC ) I ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}

mapper.update:
update item
set item_usage = 'N'
where item_id = #{itemId}
